// src/views/user/MyProfile/composables/useModules.js
import { ref, computed } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'
import { useProfileData } from './useProfileData'
import profile from '@/api/profile'

// 所有可用的模块配置
const MODULES_CONFIG = {
  job_intention: { 
    order: 1, 
    visible: true,
    name: '求职意向',
    required: false
  },
  work_experience: { 
    order: 2, 
    visible: true,
    name: '工作经历',
    required: false
  },
  education: { 
    order: 3, 
    visible: false,
    name: '教育经历'
  },
  project: { 
    order: 4, 
    visible: false,
    name: '项目经历'
  },
  skill: { 
    order: 5, 
    visible: false,
    name: '专业技能'
  },
  certificate: { 
    order: 6, 
    visible: false,
    name: '证书奖项'
  },
  language: { 
    order: 7, 
    visible: false,
    name: '语言能力'
  },
  portfolio: { 
    order: 8, 
    visible: false,
    name: '作品展示'
  },
  social_link: { 
    order: 9, 
    visible: false,
    name: '社交主页'
  }
}

export function useModules() {
  const { fetchModuleData } = useProfileData()
  const loading = ref(false)
  const modules = ref(new Map())
  const activeModulesList = ref([])

  // 计算属性保持不变，但从 activeModulesList 读取数据
  const activeModules = computed(() => activeModulesList.value)

  // 计算属性：未激活的模块
  const inactiveModules = computed(() => 
    Array.from(modules.value.values())
      .filter(m => !m.visible && !m.required)
      .sort((a, b) => a.order - b.order)
  )

  // 初始化模块状态
  const initModules = () => {
    const modulesMap = new Map()
    Object.entries(MODULES_CONFIG).forEach(([key, config]) => {
      modulesMap.set(key, {
        type: key,
        name: config.name,
        order: config.order,
        visible: config.visible,
        required: config.required || false,
        data: null
      })
    })
    modules.value = modulesMap
  }

  // 获取模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true

      // 获取求职意向数据
      const jobIntentionRes = await profile.jobIntention.get()
      console.log('求职意向响应:', jobIntentionRes)
      const jobIntentionData = jobIntentionRes?.data || {}

      // 获取工作经历数据
      const workExperienceRes = await profile.workExperience.get()
      console.log('工作经历响应:', workExperienceRes)
      const workExperienceData = workExperienceRes?.data || []

      // 更新模块数据
      activeModulesList.value = [
        {
          type: 'job_intention',
          name: '求职意向',
          visible: true,
          order: 1,
          data: jobIntentionData
        },
        {
          type: 'work_experience',
          name: '工作经历',
          visible: true,
          order: 2,
          data: workExperienceData
        }
      ]

      // 更新模块状态
      const modulesMap = new Map()
      activeModulesList.value.forEach(module => {
        modulesMap.set(module.type, {
          ...module,
          visible: true
        })
      })

      // 添加未激活的模块
      Object.entries(MODULES_CONFIG)
        .filter(([key]) => !modulesMap.has(key))
        .forEach(([key, config]) => {
          modulesMap.set(key, {
            type: key,
            name: config.name,
            order: config.order,
            visible: false,
            required: config.required || false,
            data: null
          })
        })

      modules.value = modulesMap

    } catch (error) {
      console.error('获取模块数据失败:', error)
      ElMessage.error('获取数据失败，请稍后重试')
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    try {
      const module = modules.value.get(moduleType)
      if (!module || module.required) {
        throw new Error('该模块不能被移除')
      }

      loading.value = true

      // 1. 获取当前完整布局
      const layout = {}
      Object.keys(MODULES_CONFIG).forEach(key => {
        const module = modules.value.get(key)
        layout[key] = {
          order: module.order,
          visible: key === moduleType ? false : module.visible
        }
      })

      console.log('发送的布局数据:', layout)

      // 2. 更新服务器布局
      const response = await user.updateProfileLayout({ 
        data: { layout }  // 保持与 API 接口一致的数据结构
      })

      if (response.data?.code === 200) {
        // 3. 更新本地状态
        module.visible = false
        module.data = null
        showToast('模块已移除', 'success')

        // 4. 重新获取数据以确保同步
        await fetchModulesData()
      }
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast(error.message || '移除模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      const module = modules.value.get(moduleType)
      if (!module) {
        throw new Error('模块不存在')
      }

      loading.value = true

      // 1. 获取当前完整布局
      const layout = {}
      Object.keys(MODULES_CONFIG).forEach(key => {
        const module = modules.value.get(key)
        layout[key] = {
          order: key === moduleType ? activeModules.value.length + 1 : module.order,
          visible: key === moduleType ? true : module.visible
        }
      })

      console.log('发送的布局数据:', layout)

      // 2. 更新服务器布局
      const response = await user.updateProfileLayout({ 
        data: { layout }  // 保持与 API 接口一致的数据结构
      })

      if (response.data?.code === 200) {
        // 3. 更新本地状态
        module.visible = true
        module.order = activeModules.value.length + 1

        // 4. 获取模块数据
        module.data = await fetchModuleData(moduleType)

        showToast('模块已添加', 'success')

        // 5. 重新获取数据以确保同步
        await fetchModulesData()
      }
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast(error.message || '添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,
    removeModule
  }
}
